namespace sv_67d6a1def6674a75bf1e885e40b977da.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_67d6a1def6674a75bf1e885e40b977da.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="d-flex">
        @* ─── Left Sidebar (Filters) ─── *@
        <div class="pe-4" style="min-width: 25%; max-width: 25%;">
            <div class="card">
                <div class="card-header fw-semibold">Filters</div>
                <div class="card-body">
                    @* Category checkboxes *@
                    <h6>Category</h6>
                    @if (_categories is null)
                    {
                        <p class="text-muted small">Loading…</p>
                    }
                    else
                    {
                        @foreach (var cat in _categories)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                       checked="@(_selectedCategories.Contains(cat))"
                                       @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                                <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                            </div>
                        }
                    }

                    <hr />

                    @* Price range *@
                    <h6>Price Range</h6>
                    <div class="mb-2">
                        <label class="form-label small mb-0">Min Price</label>
                        <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                               @bind="_minPrice" @bind:event="oninput" placeholder="0.00" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label small mb-0">Max Price</label>
                        <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                               @bind="_maxPrice" @bind:event="oninput" placeholder="No limit" />
                    </div>

                    <hr />

                    @* In stock toggle *@
                    <div class="form-check form-switch mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly"
                               @bind="_inStockOnly" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    @* Action buttons *@
                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync" disabled="@_loading">
                            Apply Filters
                        </button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync" disabled="@_loading">
                            Clear Filters
                        </button>
                    </div>
                </div>
            </div>
        </div>

        @* ─── Main Content ─── *@
        <div style="flex: 1; min-width: 0;">
            @if (_loading)
            {
                <div class="d-flex justify-content-center align-items-center" style="min-height: 300px;">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                </div>
            }
            else if (_result is not null)
            {
                @* Toolbar *@
                <div class="d-flex justify-content-between align-items-center mb-3">
                    <div>
                        <label class="form-label small mb-0 me-2">Sort by:</label>
                        <select class="form-select form-select-sm d-inline-block w-auto"
                                @bind="_sortBy" @bind:after="SortChangedAsync">
                            <option value="price_asc">Price: Low to High</option>
                            <option value="price_desc">Price: High to Low</option>
                            <option value="name_asc">Name: A–Z</option>
                            <option value="rating_desc">Rating: Highest</option>
                        </select>
                    </div>
                    <span class="text-muted small">
                        Showing @(_rangeStart)–@(_rangeEnd) of @_result.TotalCount products
                    </span>
                </div>

                @if (_result.Items.Count == 0)
                {
                    <div class="alert alert-info text-center" role="alert">
                        No products match your filters. Try adjusting your criteria.
                    </div>
                }
                else
                {
                    @* Product Grid *@
                    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3 mb-4">
                        @foreach (var product in _result.Items)
                        {
                            <div class="col">
                                <div class="card h-100 shadow-sm product-card"
                                     style="cursor: pointer;"
                                     @onclick="() => OnProductSelected.InvokeAsync(product.Id)">
                                    @* Placeholder image *@
                                    <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
                                         style="height: 180px;" role="img" aria-label="@product.Name">
                                        <span class="text-muted">📷 @product.Name</span>
                                    </div>
                                    <div class="card-body d-flex flex-column">
                                        <h6 class="card-title">@product.Name</h6>
                                        <p class="card-text fw-bold text-primary mb-1">
                                            @product.Price.ToString("C")
                                        </p>
                                        <p class="card-text mb-1">@RenderStars(product.Rating)</p>
                                        @if (!product.InStock)
                                        {
                                            <span class="badge bg-danger mb-2">Out of Stock</span>
                                        }
                                        <div class="mt-auto">
                                            <button class="btn btn-sm btn-success w-100"
                                                    disabled="@(!product.InStock)"
                                                    @onclick="() => AddToCart(product.Id)"
                                                    @onclick:stopPropagation="true">
                                                Add to Cart
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>

                    @* Pagination *@
                    <nav aria-label="Product pagination">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(_currentPage <= 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)"
                                        disabled="@(_currentPage <= 1)">Previous</button>
                            </li>
                            @for (var i = 1; i <= _totalPages; i++)
                            {
                                var pageNum = i;
                                <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(pageNum)">@pageNum</button>
                                </li>
                            }
                            <li class="page-item @(_currentPage >= _totalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)"
                                        disabled="@(_currentPage >= _totalPages)">Next</button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </div>
    </div>
}

@code {
    [Parameter] public EventCallback<int> OnProductSelected { get; set; }

    private const int PageSize = 9;

    // Filter state
    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    // Search state
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private PagedResult<Product>? _result;

    // UI state
    private bool _loading = true;
    private string? _error;

    // Computed
    private int _totalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / PageSize);
    private int _rangeStart => _result is null || _result.TotalCount == 0
        ? 0
        : (_result.Page - 1) * _result.PageSize + 1;
    private int _rangeEnd => _result is null || _result.TotalCount == 0
        ? 0
        : Math.Min(_result.Page * _result.PageSize, _result.TotalCount);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProductsAsync();

            _categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task SearchProductsAsync()
    {
        _loading = true;

        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );

        _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
        _loading = false;
    }

    private async Task ApplyFiltersAsync()
    {
        try
        {
            _error = null;
            _currentPage = 1;
            await SearchProductsAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task ClearFiltersAsync()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _sortBy = "price_asc";
        await ApplyFiltersAsync();
    }

    private async Task SortChangedAsync()
    {
        _currentPage = 1;
        try
        {
            _error = null;
            await SearchProductsAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task GoToPageAsync(int page)
    {
        if (page < 1 || page > _totalPages || page == _currentPage) return;
        _currentPage = page;
        try
        {
            _error = null;
            await SearchProductsAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        _error = null;
        _loading = true;
        try
        {
            _categories ??= await ProductService.GetCategoriesAsync();
            await SearchProductsAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private void AddToCart(int productId)
    {
        // Placeholder for cart integration
    }

    private static string RenderStars(double rating)
    {
        var rounded = (int)Math.Round(rating);
        return new string('★', rounded) + new string('☆', 5 - rounded);
    }
}

